#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid;
 int status;

 pid = fork(); // Create child process

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process
 printf("Child: PID = %d, Parent PID = %d\n", getpid(), getppid());
 printf("Child: Doing some work...\n");
 sleep(2); // Simulate work
 printf("Child: Exiting with status 42\n");
 exit(42); // Terminate with exit status
 } else {
 // Parent process
 printf("Parent: PID = %d, Child PID = %d\n", getpid(), pid);
 printf("Parent: Waiting for child...\n");

 pid_t terminated_pid = wait(&status); // Block until child terminates

 if (WIFEXITED(status)) {
 printf("Parent: Child %d terminated with status: %d\n", 
 terminated_pid, WEXITSTATUS(status));
 }
 printf("Parent: Child reaped, no zombie created\n");
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

int main() {
 pid_t pid;

 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process
 printf("Child: Exiting immediately\n");
 exit(0); // Child terminates immediately
 } else {
 // Parent process - DOES NOT call wait()
 printf("Parent: Sleeping without calling wait()\n");
 printf("Parent: Child %d is now ZOMBIE\n", pid);
 sleep(10); // Parent sleeps, child already terminated
 printf("Parent: Still alive, zombie exists\n");
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <sys/wait.h>

void sigchld_handler(int sig) {
 int status;
 pid_t pid;

 // Reap all terminated children
 while ((pid = waitpid(-1, &status, WNOHANG)) > 0) {
 if (WIFEXITED(status)) {
 printf("Handler: Child %d exited with status %d\n", 
 pid, WEXITSTATUS(status));
 }
 }
}

int main() {
 struct sigaction sa;
 sa.sa_handler = sigchld_handler;
 sigemptyset(&sa.sa_mask);
 sa.sa_flags = SA_RESTART | SA_NOCLDSTOP;

 if (sigaction(SIGCHLD, &sa, NULL) == -1) {
 perror("sigaction failed");
 exit(1);
 }

 // Create multiple child processes
 for (int i = 0; i < 3; i++) {
 if (fork() == 0) {
 printf("Child %d: Working...\n", getpid());
 sleep(1);
 printf("Child %d: Done\n", getpid());
 exit(i + 1);
 }
 }

 // Parent continues without blocking
 printf("Parent: Created children, doing other work\n");
 sleep(5);
 printf("Parent: All children reaped by signal handler\n");

 return 0;
}
